    45→func TestPyPIFetchNewReleases(t *testing.T) {
    46→	srv := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
    47→		w.Header().Set("Content-Type", "application/json")
    48→		w.Write([]byte(samplePyPIResponse))
    49→	}))
    50→	defer srv.Close()
    51→
    52→	src := NewPyPISource(srv.Client(), "requests", "src-id")
    53→	src.baseURL = srv.URL
    54→
    55→	results, err := src.FetchNewReleases(context.Background())
    56→	if err != nil {
    57→		t.Fatalf("FetchNewReleases: %v", err)
    58→	}
    59→
    60→	// 3 results: 2.31.0, 2.32.0, 2.33.0a1 — 0.0.0 has no files so it's skipped
    61→	if len(results) != 3 {
    62→		t.Fatalf("got %d results, want 3", len(results))
    63→	}
    64→
    65→	// Build a map for stable assertions (map iteration order is random)
    66→	byVersion := map[string]IngestionResult{}
    67→	for _, r := range results {
    68→		byVersion[r.RawVersion] = r
    69→	}
    70→
    71→	// Check 2.31.0
    72→	r, ok := byVersion["2.31.0"]
    73→	if !ok {
    74→		t.Fatal("missing version 2.31.0")
    75→	}
    76→	if r.Repository != "requests" {
    77→		t.Errorf("Repository = %q, want %q", r.Repository, "requests")
    78→	}
    79→	if r.Timestamp.IsZero() {
    80→		t.Error("Timestamp should not be zero for 2.31.0")
    81→	}
    82→	if r.Metadata["release_url"] == "" {
    83→		t.Error("Metadata[release_url] should not be empty")
    84→	}
    85→
    86→	// Check 2.32.0 — should pick earliest upload time
    87→	r2 := byVersion["2.32.0"]
    88→	if r2.Timestamp.IsZero() {
    89→		t.Error("Timestamp should not be zero for 2.32.0")
    90→	}
    91→
    92→	// Check prerelease present
    93→	if _, ok := byVersion["2.33.0a1"]; !ok {
    94→		t.Error("missing prerelease version 2.33.0a1")
    95→	}
    96→
    97→	// Yanked/empty version should be excluded
    98→	if _, ok := byVersion["0.0.0"]; ok {
    99→		t.Error("version 0.0.0 with no files should be excluded")
   100→	}
   101→}
