     2→
     3→import (
     4→	"context"
     5→	"encoding/json"
     6→	"fmt"
     7→	"net/http"
     8→	"time"
     9→)
    10→
    11→const defaultPyPIBaseURL = "https://pypi.org"
    12→
    13→// pypiRelease represents version-level metadata from the PyPI JSON API.
    14→type pypiRelease struct {
    15→	UploadTime string `json:"upload_time_iso_8601"`
    16→}
    17→
    18→// pypiProject represents the top-level response from the PyPI JSON API.
    19→type pypiProject struct {
    20→	Info struct {
    21→		Name    string `json:"name"`
    22→		Summary string `json:"summary"`
    23→	} `json:"info"`
    24→	Releases map[string][]pypiRelease `json:"releases"`
    25→}
    26→
    27→// PyPISource polls the PyPI JSON API for package releases.
    28→type PyPISource struct {
    29→	client   *http.Client
    30→	pkg      string
    31→	baseURL  string
    32→	sourceID string
    33→}
    34→
    35→func NewPyPISource(client *http.Client, pkg string, sourceID string) *PyPISource {
    36→	return &PyPISource{
    37→		client:   client,
    38→		pkg:      pkg,
    39→		baseURL:  defaultPyPIBaseURL,
    40→		sourceID: sourceID,
    41→	}
    42→}
    43→
    44→func (s *PyPISource) Name() string    { return "pypi" }
    45→func (s *PyPISource) SourceID() string { return s.sourceID }
    46→
    47→func (s *PyPISource) FetchNewReleases(ctx context.Context) ([]IngestionResult, error) {
    48→	url := fmt.Sprintf("%s/pypi/%s/json", s.baseURL, s.pkg)
    49→
    50→	req, err := http.NewRequestWithContext(ctx, http.MethodGet, url, nil)
    51→	if err != nil {
    52→		return nil, fmt.Errorf("create request: %w", err)
    53→	}
    54→	req.Header.Set("Accept", "application/json")
    55→
    56→	resp, err := s.client.Do(req)
    57→	if err != nil {
    58→		return nil, fmt.Errorf("fetch releases: %w", err)
    59→	}
    60→	defer resp.Body.Close()
    61→
    62→	if resp.StatusCode != http.StatusOK {
    63→		return nil, fmt.Errorf("unexpected status: %d", resp.StatusCode)
    64→	}
    65→
    66→	var project pypiProject
    67→	if err := json.NewDecoder(resp.Body).Decode(&project); err != nil {
    68→		return nil, fmt.Errorf("decode response: %w", err)
    69→	}
    70→
    71→	results := make([]IngestionResult, 0, len(project.Releases))
    72→	for version, files := range project.Releases {
    73→		if version == "" {
    74→			continue
    75→		}
    76→		// Skip versions with no files (yanked/empty).
    77→		if len(files) == 0 {
    78→			continue
    79→		}
    80→
    81→		// Use the earliest upload timestamp from the version's files.
    82→		var ts time.Time
    83→		for _, f := range files {
    84→			if f.UploadTime != "" {
    85→				parsed, err := time.Parse(time.RFC3339, f.UploadTime)
    86→				if err == nil {
    87→					if ts.IsZero() || parsed.Before(ts) {
    88→						ts = parsed
    89→					}
    90→				}
    91→			}
    92→		}
    93→
    94→		releaseURL := fmt.Sprintf("%s/project/%s/%s/", s.baseURL, s.pkg, version)
    95→
    96→		results = append(results, IngestionResult{
    97→			Repository: s.pkg,
    98→			RawVersion: version,
    99→			Changelog:  "",
   100→			Metadata: map[string]string{
   101→				"release_url": releaseURL,
   102→			},
   103→			Timestamp: ts,
   104→		})
   105→	}
   106→	return results, nil
   107→}
