     1→export function timeAgo(dateStr?: string | null): string {
     2→  if (!dateStr) return "\u2014";
     3→  const diff = Date.now() - new Date(dateStr).getTime();
     4→  const mins = Math.floor(diff / 60000);
     5→  if (mins < 60) return `${mins}m ago`;
     6→  const hrs = Math.floor(mins / 60);
     7→  if (hrs < 24) return `${hrs}h ago`;
     8→  return `${Math.floor(hrs / 24)}d ago`;
     9→}
    10→
    11→export function validateRepository(provider: string, repo: string): string | null {
    12→  const trimmed = repo.trim();
    13→  if (!trimmed) return null;
    14→  if (provider === "github" && /^(https?:\/\/)?github\.com\//i.test(trimmed)) {
    15→    return "Use owner/repo format (e.g. ethereum/go-ethereum), not a full URL";
    16→  }
    17→  if (provider === "dockerhub" && /^(https?:\/\/)?hub\.docker\.com\//i.test(trimmed)) {
    18→    return "Use owner/image format (e.g. library/nginx), not a full URL";
    19→  }
    20→  if (provider === "ecr-public" && /^(https?:\/\/)?(gallery\.ecr\.aws|public\.ecr\.aws)\//i.test(trimmed)) {
    21→    return "Use alias/repo format (e.g. i6b2w2n6/op-node), not a full URL";
    22→  }
    23→  if (provider === "gitlab" && /^(https?:\/\/)?gitlab\.com\//i.test(trimmed)) {
    24→    return "Use owner/repo format (e.g. inkscape/inkscape), not a full URL";
    25→  }
    26→  if (provider === "pypi" && /^(https?:\/\/)?pypi\.org\//i.test(trimmed)) {
    27→    return "Use package name format (e.g. requests), not a full URL";
    28→  }
    29→  if (/^https?:\/\//.test(trimmed)) {
    30→    return "Use owner/repo format, not a full URL";
    31→  }
    32→  return null;
    33→}
    34→
    35→export function formatInterval(seconds: number): string {
    36→  if (seconds === 3600) return "Hourly";
    37→  if (seconds === 86400) return "Daily";
    38→  if (seconds === 604800) return "Weekly";
    39→  if (seconds === 2592000) return "Monthly";
    40→  if (seconds < 60) return `${seconds}s`;
    41→  if (seconds < 3600) return `${Math.round(seconds / 60)}m`;
    42→  if (seconds < 86400) return `${(seconds / 3600).toFixed(1)}h`;
    43→  return `${(seconds / 86400).toFixed(1)}d`;
    44→}
