	"fmt"
	"net/http"
	"time"
)

const defaultPyPIBaseURL = "https://pypi.org"

// pypiRelease represents version-level metadata from the PyPI JSON API.
type pypiRelease struct {
	UploadTime string `json:"upload_time_iso_8601"`
}

// pypiProject represents the top-level response from the PyPI JSON API.
type pypiProject struct {
	Info struct {
		Name    string `json:"name"`
		Summary string `json:"summary"`
	} `json:"info"`
	Releases map[string][]pypiRelease `json:"releases"`
}

// PyPISource polls the PyPI JSON API for package releases.
type PyPISource struct {
	client   *http.Client
	pkg      string
	baseURL  string
	sourceID string
}

func NewPyPISource(client *http.Client, pkg string, sourceID string) *PyPISource {
	return &PyPISource{
		client:   client,
		pkg:      pkg,
		baseURL:  defaultPyPIBaseURL,
		sourceID: sourceID,
	}
}

func (s *PyPISource) Name() string    { return "pypi" }
func (s *PyPISource) SourceID() string { return s.sourceID }

func (s *PyPISource) FetchNewReleases(ctx context.Context) ([]IngestionResult, error) {
	url := fmt.Sprintf("%s/pypi/%s/json", s.baseURL, s.pkg)

	req, err := http.NewRequestWithContext(ctx, http.MethodGet, url, nil)
	if err != nil {
		return nil, fmt.Errorf("create request: %w", err)
	}
	req.Header.Set("Accept", "application/json")

	resp, err := s.client.Do(req)
	if err != nil {
		return nil, fmt.Errorf("fetch releases: %w", err)
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return nil, fmt.Errorf("unexpected status: %d", resp.StatusCode)
	}

	var project pypiProject
	if err := json.NewDecoder(resp.Body).Decode(&project); err != nil {
		return nil, fmt.Errorf("decode response: %w", err)
	}

	results := make([]IngestionResult, 0, len(project.Releases))
	for version, files := range project.Releases {
		if version == "" {
			continue
		}
		// Skip versions with no files (yanked/empty).
		if len(files) == 0 {
			continue
		}

		// Use the earliest upload timestamp from the version's files.
		var ts time.Time
		for _, f := range files {
			if f.UploadTime != "" {
				parsed, err := time.Parse(time.RFC3339, f.UploadTime)
				if err == nil {
					if ts.IsZero() || parsed.Before(ts) {
						ts = parsed
					}
				}
			}
		}

		releaseURL := fmt.Sprintf("%s/project/%s/%s/", s.baseURL, s.pkg, version)

		results = append(results, IngestionResult{
			Repository: s.pkg,
			RawVersion: version,
			Changelog:  "",
			Metadata: map[string]string{
				"release_url": releaseURL,
			},
			Timestamp: ts,
		})
	}
	return results, nil
}

package ingestion

import (
	"context"
	"fmt"
	"log/slog"
	"net/http"
	"time"

	"github.com/jackc/pgx/v5/pgxpool"
)

// ScheduledSource wraps an IIngestionSource with its scheduling metadata
// so the orchestrator can decide whether the source is due for polling.
type ScheduledSource struct {
	Source              IIngestionSource
	PollIntervalSeconds int
	LastPolledAt         *time.Time
}

// SourceLoader reads source configuration from the database and constructs
// IIngestionSource instances. It bridges the API-managed sources table with
// the polling orchestrator.
type SourceLoader struct {
	pool   *pgxpool.Pool
	client *http.Client
}

func NewSourceLoader(pool *pgxpool.Pool, client *http.Client) *SourceLoader {
	return &SourceLoader{pool: pool, client: client}
}

// LoadEnabledSources queries all enabled sources and constructs the
// appropriate IIngestionSource for each one, along with scheduling metadata.
func (l *SourceLoader) LoadEnabledSources(ctx context.Context) ([]ScheduledSource, error) {
	rows, err := l.pool.Query(ctx,
		`SELECT id, provider, repository, poll_interval_seconds, last_polled_at
		 FROM sources WHERE enabled = true`)
	if err != nil {
		return nil, fmt.Errorf("query enabled sources: %w", err)
	}
	defer rows.Close()

	var sources []ScheduledSource
	for rows.Next() {
		var id string
		var sourceType, repository string
		var pollInterval int
		var lastPolledAt *time.Time
		if err := rows.Scan(&id, &sourceType, &repository, &pollInterval, &lastPolledAt); err != nil {
			return nil, fmt.Errorf("scan source row: %w", err)
		}

		src := l.buildSource(id, sourceType, repository)
		if src == nil {
			slog.Warn("unsupported source type, skipping",
				"id", id, "type", sourceType, "repo", repository)
			continue
		}
		sources = append(sources, ScheduledSource{
			Source:              src,
			PollIntervalSeconds: pollInterval,
			LastPolledAt:         lastPolledAt,
		})
	}
	return sources, rows.Err()
}

// LookupSourceID finds the source ID for a given (provider, repository) pair.
// Returns empty string and false if no matching enabled source exists.
func (l *SourceLoader) LookupSourceID(ctx context.Context, provider, repository string) (string, bool) {
	var id string
	err := l.pool.QueryRow(ctx,
		`SELECT id FROM sources WHERE provider = $1 AND repository = $2 AND enabled = true`,
		provider, repository,
	).Scan(&id)
	if err != nil {
		return "", false
	}
	return id, true
}

func (l *SourceLoader) buildSource(id string, sourceType, repository string) IIngestionSource {
	return BuildSource(l.client, id, sourceType, repository)
}

// BuildSource constructs the appropriate IIngestionSource based on provider type.
func BuildSource(client *http.Client, id string, sourceType, repository string) IIngestionSource {
	switch sourceType {
	case "dockerhub":
		return NewDockerHubSource(client, repository, id)
	case "github":
		return NewGitHubSource(client, repository, id)
	case "ecr-public":
		return NewECRPublicSource(client, repository, id)
	case "gitlab":
		return NewGitLabSource(client, repository, id)
	case "pypi":
		return NewPyPISource(client, repository, id)
	default:
		return nil
	}
}

package api

import "net/http"

// ProvidersHandler implements HTTP handlers for the /providers resource.
// Returns static metadata about supported ingestion providers — no store needed.
type ProvidersHandler struct{}

// NewProvidersHandler returns a new ProvidersHandler.
func NewProvidersHandler() *ProvidersHandler {
	return &ProvidersHandler{}
}

// List handles GET /providers — returns the list of supported ingestion providers.
func (h *ProvidersHandler) List(w http.ResponseWriter, r *http.Request) {
	providers := []map[string]string{
		{"id": "dockerhub", "name": "Docker Hub", "type": "polling"},
		{"id": "github", "name": "GitHub", "type": "webhook"},
		{"id": "ecr-public", "name": "AWS ECR Public", "type": "polling"},
		{"id": "gitlab", "name": "GitLab", "type": "polling"},
		{"id": "pypi", "name": "PyPI", "type": "polling"},
	}
	RespondJSON(w, r, http.StatusOK, providers)
}

