function DetailRow({
  label,
  value,
  mono,
  small,
}: {
  label: string;
  value: string;
  mono?: boolean;
  small?: boolean;
}) {
  return (
    <div className="flex items-baseline justify-between gap-4">
      <span
        style={{
          fontFamily: "var(--font-dm-sans)",
          fontSize: "13px",
          color: "#9ca3af",
        }}
      >
        {label}
      </span>
      <span
        className="text-right"
        style={{
          fontFamily: mono ? "'JetBrains Mono', monospace" : "var(--font-dm-sans)",
          fontSize: small ? "11px" : "13px",
          color: "#374151",
        }}
      >
        {value}
      </span>
    </div>
  );
}

